 10→
 11→import androidx.annotation.NonNull;
 12→import androidx.appcompat.app.AlertDialog;
 13→import androidx.appcompat.app.AppCompatDialogFragment;
 14→import androidx.appcompat.view.ContextThemeWrapper;
 15→
 16→import com.google.android.material.dialog.MaterialAlertDialogBuilder;
 17→
 18→import org.wordpress.android.R;
 19→import org.wordpress.android.WordPress;
 20→import org.wordpress.android.fluxc.model.SiteModel;
 21→import org.wordpress.android.fluxc.model.TermModel;
 22→import org.wordpress.android.fluxc.store.TaxonomyStore;
 23→import org.wordpress.android.models.CategoryNode;
 24→import org.wordpress.android.util.ToastUtils;
 25→
 26→import java.util.ArrayList;
 27→
 28→import javax.inject.Inject;
 29→
 30→public class AddCategoryFragment extends AppCompatDialogFragment {
 31→    private SiteModel mSite;
 32→    private EditText mCategoryEditText;
 33→    private Spinner mParentSpinner;
 34→
 35→    @Inject TaxonomyStore mTaxonomyStore;
 36→
 37→    public static AddCategoryFragment newInstance(SiteModel site) {
 38→        AddCategoryFragment fragment = new AddCategoryFragment();
 39→        Bundle bundle = new Bundle();
 40→        bundle.putSerializable(WordPress.SITE, site);
 41→        fragment.setArguments(bundle);
 42→        return fragment;
 43→    }
 44→
 45→    @Override
 46→    @NonNull
 47→    public Dialog onCreateDialog(Bundle savedInstanceState) {
 48→        ((WordPress) requireActivity().getApplication()).component().inject(this);
 49→
 50→        initSite(savedInstanceState);
 51→
 52→        AlertDialog.Builder builder =
 53→                new MaterialAlertDialogBuilder(new ContextThemeWrapper(getActivity(), R.style.PostSettingsTheme));
 54→        // Get the layout inflater
 55→        LayoutInflater inflater = requireActivity().getLayoutInflater();
 56→
 57→        // Inflate view
 58→        //noinspection InflateParams
 59→        View view = inflater.inflate(R.layout.add_category, null);
 60→        mCategoryEditText = (EditText) view.findViewById(R.id.category_name);
 61→        mParentSpinner = (Spinner) view.findViewById(R.id.parent_category);
 62→
 63→        loadCategories();
 64→
 65→        builder.setView(view)
 66→               .setPositiveButton(android.R.string.ok, null)
 67→               .setNegativeButton(android.R.string.cancel, null);
 68→
 69→        return builder.create();
 70→    }
 71→
 72→    @Override
 73→    public void onStart() {
 74→        super.onStart();
 75→        AlertDialog dialog = (AlertDialog) requireDialog();
 76→        dialog.getButton(DialogInterface.BUTTON_POSITIVE).setOnClickListener(new View.OnClickListener() {
 77→            @Override
 78→            public void onClick(View v) {
 79→                if (addCategory()) {
 80→                    dismiss();
 81→                }
 82→            }
 83→        });
 84→    }
 85→
 86→    private void initSite(Bundle savedInstanceState) {
 87→        if (savedInstanceState == null) {
 88→            if (getArguments() != null) {
 89→                mSite = (SiteModel) getArguments().getSerializable(WordPress.SITE);
 90→            } else {
 91→                mSite = (SiteModel) requireActivity().getIntent().getSerializableExtra(WordPress.SITE);
 92→            }
 93→        } else {
 94→            mSite = (SiteModel) savedInstanceState.getSerializable(WordPress.SITE);
 95→        }
 96→
 97→        if (mSite == null) {
 98→            ToastUtils.showToast(requireActivity(), R.string.blog_not_found, ToastUtils.Duration.SHORT);
 99→            getParentFragmentManager().popBackStack();
100→        }
101→    }
102→
103→    private boolean addCategory() {
104→        String categoryName = mCategoryEditText.getText().toString();
105→        CategoryNode selectedCategory = (CategoryNode) mParentSpinner.getSelectedItem();
106→        long parentId = (selectedCategory != null) ? selectedCategory.getCategoryId() : 0;
107→
108→        if (categoryName.replaceAll(" ", "").equals("")) {
109→            mCategoryEditText.setError(getText(R.string.cat_name_required));
110→            return false;
111→        }
112→
113→        TermModel newCategory = new TermModel(
114→                TaxonomyStore.DEFAULT_TAXONOMY_CATEGORY,
115→                categoryName,
116→                parentId
117→        );
118→        ((SelectCategoriesActivity) requireActivity()).categoryAdded(newCategory);
119→
120→        return true;
121→    }
122→
123→    private void loadCategories() {
124→        CategoryNode rootCategory = CategoryNode.createCategoryTreeFromList(mTaxonomyStore.getCategoriesForSite(mSite));
125→        ArrayList<CategoryNode> categoryLevels = CategoryNode.getSortedListOfCategoriesFromRoot(rootCategory);
126→        categoryLevels.add(0, new CategoryNode(0, 0, getString(R.string.top_level_category_name)));
127→        if (categoryLevels.size() > 0) {
128→            ParentCategorySpinnerAdapter categoryAdapter =
129→                    new ParentCategorySpinnerAdapter(getActivity(), R.layout.categories_row_parent, categoryLevels);
130→            mParentSpinner.setAdapter(categoryAdapter);
131→        }
132→    }
133→
134→    @Override
135→    public void onSaveInstanceState(Bundle outState) {
136→        super.onSaveInstanceState(outState);
137→        outState.putSerializable(WordPress.SITE, mSite);
138→    }
139→}
